Here is a simple implementation of Depth-First Search (DFS) in C++ using an adjacency list representation of the graph:

```cpp
#include <iostream>
#include <vector>
#include <stack>

using namespace std;

class Graph {
private:
    int V; // Number of vertices
    vector<int> *adj; // Pointer to an array containing adjacency lists

public:
    Graph(int V); // Constructor
    void addEdge(int v, int w); // Function to add an edge to graph
    void DFSUtil(int v, bool visited[]); // A utility function used by DFS
    void DFS(); // DFS traversal of the vertices reachable from v
};

Graph::Graph(int V) {
    this->V = V;
    adj = new vector<int>[V];
}

void Graph::addEdge(int v, int w) {
    adj[v].push_back(w); // Add w to v’s list.
}

void Graph::DFSUtil(int v, bool visited[]) {
    // Mark the current node as visited and print it
    visited[v] = true;
    cout << v << " ";

    // Recur for all the vertices adjacent to this vertex
    for (int i = 0; i < adj[v].size(); ++i)
        if (!visited[adj[v][i]])
            DFSUtil(adj[v][i], visited);
}

void Graph::DFS() {
    // Mark all the vertices as not visited
    bool *visited = new bool[V];
    for (int i = 0; i < V; i++)
        visited[i] = false;

    // Call the recursive helper function to print DFS traversal
    // starting from all vertices one by one
    for (int i = 0; i < V; i++)
        if (!visited[i])
            DFSUtil(i, visited);
}

// Driver code
int main() {
    Graph g(4); // Create a graph with 4 vertices
    g.addEdge(0, 1);
    g.addEdge(0, 2);
    g.addEdge(1, 2);
    g.addEdge(2, 0);
    g.addEdge(2, 3);
    g.addEdge(3, 3);

    cout << "Following is Depth First Traversal (starting from vertex 2) \n";
    g.DFS();

    return 0;
}
```

This code defines a `Graph` class with methods to add edges and perform DFS. The `DFSUtil` function is a recursive helper that performs the actual DFS traversal, while the `DFS` function initializes the visited array and calls `DFSUtil` for each vertex.

You can modify this code according to your specific requirements.

Here is a simple implementation of Depth-First Search (DFS) in JavaScript using an adjacency list representation of the graph:

```javascript
class Graph {
    constructor() {
        this.adjacencyList = {};
    }

    addVertex(vertex) {
        if (!this.adjacencyList[vertex]) {
            this.adjacencyList[vertex] = [];
        }
    }

    addEdge(vertex1, vertex2) {
        this.adjacencyList[vertex1].push(vertex2);
        this.adjacencyList[vertex2].push(vertex1); // For undirected graph
    }

    DFS(startingVertex) {
        const visited = {};
        const stack = [startingVertex];

        while (stack.length > 0) {
            const vertex = stack.pop();
            if (!visited[vertex]) {
                console.log(vertex);
                visited[vertex] = true;
                this.adjacencyList[vertex].forEach(neighbor => {
                    if (!visited[neighbor]) {
                        stack.push(neighbor);
                    }
                });
            }
        }
    }
}

// Example usage:
const graph = new Graph();
graph.addVertex('A');
graph.addVertex('B');
graph.addVertex('C');
graph.addVertex('D');
graph.addEdge('A', 'B');
graph.addEdge('A', 'C');
graph.addEdge('B', 'D');
graph.addEdge('C', 'D');

console.log("Depth First Traversal (starting from vertex A):");
graph.DFS('A');
