#include <iostream>
#include <Eigen/Dense>
#include <armadillo>

// Function to initialize weights and biases
std::pair<Eigen::MatrixXd, Eigen::VectorXd> init_weights(int input_size, int hidden_size, int output_size) {
    Eigen::MatrixXd W1(hidden_size, input_size);
    Eigen::VectorXd b1(hidden_size);
    Eigen::MatrixXd W2(output_size, hidden_size);
    Eigen::VectorXd b2(output_size);

    // Initialize weights and biases with random values
    W1.setRandom();
    b1.setRandom();
    W2.setRandom();
    b2.setRandom();

    return {W1, b1, W2, b2};
}

// Sigmoid activation function
Eigen::MatrixXd sigmoid(const Eigen::MatrixXd& z) {
    return 1.0 / (1.0 + (-z).exp());
}

// Forward propagation
std::pair<Eigen::MatrixXd, Eigen::VectorXd> forward_propagation(const Eigen::MatrixXd& X, const std::pair<Eigen::MatrixXd, Eigen::VectorXd>& weights) {
    auto [W1, b1, W2, b2] = weights;

    Eigen::MatrixXd Z1 = W1 * X + b1;
    Eigen::MatrixXd A1 = sigmoid(Z1);
    Eigen::MatrixXd Z2 = W2 * A1 + b2;
    Eigen::MatrixXd A2 = sigmoid(Z2);

    return {A1, A2};
}

// Loss function (binary cross-entropy)
double loss(const Eigen::MatrixXd& y_true, const Eigen::MatrixXd& y_pred) {
    int m = y_true.rows();
    double epsilon = 1e-15; // To avoid log(0)

    Eigen::MatrixXd term1 = -y_true.array() * (y_pred.array().log() + epsilon);
    Eigen::MatrixXd term2 = -(1.0 - y_true.array()) * ((1.0 - y_pred.array()).log() + epsilon);

    return (term1 + term2).sum() / m;
}

// Backward propagation
std::pair<Eigen::MatrixXd, Eigen::VectorXd> backward_propagation(const Eigen::MatrixXd& X, const Eigen::MatrixXd& y_true, const std::pair<Eigen::MatrixXd, Eigen::VectorXd>& weights) {
    auto [W1, b1, W2, b2] = weights;

    auto [A1, A2] = forward_propagation(X, weights);

    int m = X.rows();

    Eigen::MatrixXd dZ2 = A2 - y_true;
    Eigen::MatrixXd dW2 = (dZ2 * A1.transpose()) / m;
    Eigen::VectorXd db2 = dZ2.colwise().sum() / m;

    Eigen::MatrixXd dZ1 = W2.transpose() * dZ2 .* (A1.array() * (1.0 - A1.array()));
    Eigen::MatrixXd dW1 = (dZ1 * X.transpose()) / m;
    Eigen::VectorXd db1 = dZ1.colwise().sum() / m;

    return {dW1, db1, dW2, db2};
}

// Update weights and biases
std::pair<Eigen::MatrixXd, Eigen::VectorXd> update_weights(const std::pair<Eigen::MatrixXd, Eigen::VectorXd>& weights, const std::pair<Eigen::MatrixXd, Eigen::VectorXd>& grads, double learning_rate) {
    auto [W1, b1, W2, b2] = weights;
    auto [dW1, db1, dW2, db2] = grads;

    Eigen::MatrixXd new_W1 = W1 - learning_rate * dW1;
    Eigen::VectorXd new_b1 = b1 - learning_rate * db1;
    Eigen::MatrixXd new_W2 = W2 - learning_rate * dW2;
    Eigen::VectorXd new_b2 = b2 - learning_rate * db2;

    return {new_W1, new_b1, new_W2, new_b2};
}

int main() {
    // Example data
    Eigen::MatrixXd X(4, 3); // 4 samples, 3 features
    X << 0.5, 0.2, 0.8,
         0.7, 0.1, 0.9,
         0.6, 0.3, 0.7,
         0.4, 0.5, 0.6;

    Eigen::MatrixXd y(4, 1); // Binary labels
    y << 0,
         1,
         0,
         1;

    int input_size = X.cols();
    int hidden_size = 2;
    int output_size = 1;

    auto [W1, b1, W2, b2] = init_weights(input_size, hidden_size, output_size);

    double learning_rate = 0.1;
    int epochs = 1000;

    for (int epoch = 0; epoch < epochs; ++epoch) {
        auto grads = backward_propagation(X, y, {W1, b1, W2, b2});
        auto [new_W1, new_b1, new_W2, new_b2] = update_weights({W1, b1, W2, b2}, grads, learning_rate);

        W1 = new_W1;
        b1 = new_b1;
        W2 = new_W2;
        b2 = new_b2;

        if (epoch % 100 == 0) {
            auto [A1, A2] = forward_propagation(X, {W1, b1, W2, b2});
            double current_loss = loss(y, A2);
            std::cout << "Epoch " << epoch << ", Loss: " << current_loss << std::endl;
        }
    }

    // Predict new traffic
    Eigen::MatrixXd new_traffic(1, 3);
    new_traffic << 7.2, 3.4, 9.6, 5.1;

    auto [A1, A2] = forward_propagation(new_traffic, {W1, b1, W2, b2});
    double prediction = A2(0, 0);
    std::cout << "Traffic is classified as: " << (prediction > 0.5 ? "Malicious" : "Benign") << std::endl;

    return 0;
}
